import { Injectable, inject } from '@angular/core';
import { BehaviorSubject, Observable, combineLatest, firstValueFrom } from 'rxjs';
import { map, distinctUntilChanged, debounceTime, filter, take } from 'rxjs/operators';
import { OrderHelperService } from './order-helper.service';
import { OrderStateService } from './order-state.service';
import { AuthService } from '../Base/auth.service';
import { SupabaseService } from '../Base/supabase.service';
import { DishService } from '../Piatti/dish.service';

export interface KitchenGroup {
  order_header_id: string;
  order_number?: string;
  table_number: string;
  table_name: string;
  created_at: string;
  customer_name: string;
  comande: KitchenComanda[];
  floor_plan_id?: string; 
  floor_plan_name?: string; 
  table_id?: string;
  status_summary?: {      // 👈 Aggiungi questa proprietà
    waiting: number;
    preparing: number;
    ready: number;
    served: number;
    ordered: number;
    cancelled: number;
    out_of_stock: number;
  };
}

export interface KitchenComanda {
  id: string;
  comanda_number: number;
  status: string;
  created_at: string;
  items: KitchenItem[];
  completed_items?: number;
  total_items?: number;
  progress_percentage?: number;
}

export interface KitchenItem {
  id: string;
  dish_id: string;
  dish_name: string;
  quantity: number;
  status: string;
  notes: string;
  special_requests: string;
  created_at: string;
  preparation_time: number;
  table_number: string;
}

@Injectable({ providedIn: 'root' })
export class KitchenService {
  private supabase = inject(SupabaseService).getSupabaseClient();
  private authService = inject(AuthService);
  private orderHelper = inject(OrderHelperService);
  private orderState = inject(OrderStateService);
  private dishService = inject(DishService); 

  private dishCache = new Map<string, { name: string; preparation_time: number }>();
  private dishesLoaded = false;
  private lastLoadTime: number = 0;
  private readonly CACHE_TTL = 30000; // 30 secondi

  // Filtri
  private statusFilter = new BehaviorSubject<string>('all');
  private searchTerm = new BehaviorSubject<string>('');
  private floorPlanFilter = new BehaviorSubject<string>('all');
  private rawGroups = new BehaviorSubject<KitchenGroup[]>([]);

  // Observables pubblici
  filteredGroups$: Observable<KitchenGroup[]> = combineLatest([
    this.rawGroups.asObservable(),
    this.statusFilter.asObservable(),
    this.searchTerm.asObservable().pipe(debounceTime(300)),
    this.floorPlanFilter.asObservable()
  ]).pipe(
    map(([groups, statusFilter, searchTerm, floorPlanFilter]) => 
      this.filterGroups(groups, statusFilter, searchTerm, floorPlanFilter)
    ),
    distinctUntilChanged()
  );

  stats$: Observable<{ 
    waiting: number; 
    preparing: number; 
    ready: number; 
    totalGroups: number;
    totalItems: number;
  }> = this.filteredGroups$.pipe(
    map(groups => this.calculateStats(groups))
  );

  constructor() {
    console.log('🏁 [KitchenService] Inizializzazione');
    this.initializeService();
  }

  // ==================== METODI PUBBLICI AGGIUNTI ====================

  setFloorPlanFilter(floorPlanId: string): void {
    this.floorPlanFilter.next(floorPlanId);
  }

  // Carica tutte le mappe del ristorante
  async loadFloorPlans(): Promise<{id: string, name: string}[]> {
    try {
      const restaurantId = await this.authService.getCurrentRestaurantId();
      if (!restaurantId) return [];

      const { data, error } = await this.supabase
        .from('restaurant_floor_plans')
        .select('id, name')
        .eq('restaurant_id', restaurantId)
        .eq('is_active', true)
        .order('name', { ascending: true });

      if (error) {
        console.error('Errore caricamento mappe:', error);
        return [];
      }

      return data || [];
    } catch (error) {
      console.error('Errore caricamento mappe:', error);
      return [];
    }
  }

  // Ottiene i dettagli della mappa per un tavolo
  async getFloorPlanForTable(tableId: string): Promise<{id: string, name: string} | null> {
    try {
      const { data, error } = await this.supabase
        .from('tables')
        .select(`
          restaurant_floor_plans!inner (
            id,
            name
          )
        `)
        .eq('id', tableId)
        .single();

      if (error) throw error;
      
      if (data.restaurant_floor_plans && Array.isArray(data.restaurant_floor_plans)) {
        return data.restaurant_floor_plans[0];
      }
      return null;
    } catch (error) {
      console.error('Errore recupero mappa per tavolo:', error);
      return null;
    }
  }

  // ==================== METODI PUBBLICI ESISTENTI ====================

async forceRefresh(): Promise<void> {
  console.log('🔄 [KitchenService] Forzatura refresh dati');
  await this.loadKitchenData(true); // true = force
}

  setStatusFilter(status: string): void {
    this.statusFilter.next(status);
  }

  setSearchTerm(term: string): void {
    this.searchTerm.next(term);
  }

  async updateItemStatus(itemId: string, newStatus: string): Promise<boolean> {
    return await this.orderState.updateItemStatus(itemId, newStatus);
  }

  async updateComandaStatus(comandaId: string, newStatus: string): Promise<boolean> {
    const success = await this.orderState.updateComandaStatus(comandaId, newStatus);
    if (success && ['preparing', 'ready', 'served', 'cancelled'].includes(newStatus)) {
      await this.orderState.updateAllItemsInComanda(comandaId, newStatus);
    }
    return success;
  }

  async markAllItemsInComandaAsReady(comandaId: string): Promise<boolean> {
    return await this.orderState.updateAllItemsInComanda(comandaId, 'ready');
  }

  async markAllItemsInGroupAsReady(group: KitchenGroup): Promise<boolean> {
    const promises = group.comande.map(comanda => 
      this.markAllItemsInComandaAsReady(comanda.id)
    );
    await Promise.all(promises);
    return true;
  }

  // Utility methods
  calculateElapsedTime(dateString: string): number {
    if (!dateString) return 0;
    try {
      const created = new Date(dateString);
      const now = new Date();
      return Math.max(0, Math.floor((now.getTime() - created.getTime()) / (1000 * 60)));
    } catch {
      return 0;
    }
  }

  formatTime(dateString: string): string {
    if (!dateString) return '';
    return new Date(dateString).toLocaleTimeString('it-IT', { 
      hour: '2-digit', 
      minute: '2-digit' 
    });
  }

  // ==================== METODI PRIVATI AGGIORNATI ====================

  private async loadInitialData(): Promise<void> {
    try {
      await this.loadKitchenData();
    } catch (error) {
      console.error('Errore caricamento iniziale dati cucina:', error);
    }
  }

  private calculateGroupStatusSummary(comande: KitchenComanda[]): any {
    const summary = {
      waiting: 0,
      preparing: 0,
      ready: 0,
      served: 0,
      ordered: 0,
      cancelled: 0,
      out_of_stock: 0
    };

    comande.forEach(comanda => {
      comanda.items.forEach(item => {
        const status = item.status;
        switch (status) {
          case 'waiting': summary.waiting++; break;
          case 'preparing': summary.preparing++; break;
          case 'ready': summary.ready++; break;
          case 'served': summary.served++; break;
          case 'ordered': summary.ordered++; break;
          case 'cancelled': summary.cancelled++; break;
          case 'out_of_stock': summary.out_of_stock++; break;
          default: summary.ordered++; break;
        }
      });
    });

    return summary;
  }

  private filterGroups(
    groups: KitchenGroup[], 
    statusFilter: string, 
    searchTerm: string,
    floorPlanFilter: string
  ): KitchenGroup[] {
    let filtered = groups;

    if (statusFilter !== 'all') {
      filtered = filtered.filter(group => 
        group.comande.some(comanda => 
          comanda.items.some(item => item.status === statusFilter)
        )
      );
    }

    if (searchTerm.trim()) {
      const term = searchTerm.toLowerCase();
      filtered = filtered.filter(group => 
        group.table_name.toLowerCase().includes(term) ||
        group.customer_name.toLowerCase().includes(term) ||
        group.comande.some(comanda => 
          comanda.items.some(item => item.dish_name.toLowerCase().includes(term))
        )
      );
    }

    if (floorPlanFilter !== 'all') {
      filtered = filtered.filter(group => group.floor_plan_id === floorPlanFilter);
    }

    return filtered;
  }


  private calculateStats(groups: KitchenGroup[]): any {
    const stats = {
      waiting: 0,
      preparing: 0,
      ready: 0,
      totalGroups: groups.length,
      totalItems: 0
    };

    groups.forEach(group => {
      group.comande.forEach(comanda => {
        comanda.items.forEach(item => {
          stats.totalItems++;
          if (item.status === 'waiting') stats.waiting++;
          if (item.status === 'preparing') stats.preparing++;
          if (item.status === 'ready') stats.ready++;
        });
      });
    });

    return stats;
  }


    // ==================== METODI PRIVATI ====================

private async initializeService(): Promise<void> {
  try {
    console.log('🔧 [KitchenService] Inizializzazione servizio');
    await this.loadDishes();        // senza force
    await this.loadKitchenData();
  } catch (error) {
    console.error('❌ [KitchenService] Errore inizializzazione:', error);
  }
}

private async loadDishes(force: boolean = false): Promise<void> {
  if (this.dishesLoaded && !force) {
    console.log('🍝 [KitchenService] Piatti già caricati, uso cache');
    return;
  }

  try {
    console.log('🍝 [KitchenService] Caricamento piatti...');
    await this.dishService.loadData();
    const dishes = this.dishService.getDishes();

    if (dishes.length === 0) {
      console.warn('⚠️ [KitchenService] Nessun piatto caricato');
      return;
    }

    this.updateDishCache(dishes);
    this.dishesLoaded = true;
    console.log(`✅ [KitchenService] ${dishes.length} piatti caricati`);
  } catch (error) {
    console.error('❌ [KitchenService] Errore caricamento piatti:', error);
  }
}


  private updateDishCache(dishes: any[]): void {
    this.dishCache.clear();
    
    dishes.forEach(dish => {
      if (dish && dish.id && dish.name) {
        this.dishCache.set(dish.id, {
          name: dish.name,
          preparation_time: dish.preparation_time || 15
        });
      }
    });
    
    console.log(`📦 [KitchenService] Cache piatti aggiornata: ${this.dishCache.size} piatti`);
    
    // Debug: mostra i primi 5 piatti in cache
    if (this.dishCache.size > 0) {
      const firstFive = Array.from(this.dishCache.entries()).slice(0, 5);
      console.log('🔍 [KitchenService] Primi 5 piatti in cache:', firstFive);
    }
  }

  private getDishInfo(dishId: string): { name: string; preparation_time: number } {
    if (!dishId) {
      console.warn('⚠️ [KitchenService] dishId è undefined o null');
      return {
        name: 'Piatto sconosciuto',
        preparation_time: 15
      };
    }

    // Cerca nella cache
    const cached = this.dishCache.get(dishId);
    if (cached) {
      return cached;
    }

    // Se non in cache, cerca nel DishService
    try {
      const dish = this.dishService.getDishById(dishId);
      if (dish) {
        const dishInfo = {
          name: dish.name || `Piatto #${dishId.substring(0, 4)}`,
          preparation_time: dish.preparation_time || 15
        };
        
        // Salva in cache
        this.dishCache.set(dishId, dishInfo);
        
        console.log(`✅ [KitchenService] Piatto trovato: ${dishInfo.name} (${dishId})`);
        return dishInfo;
      }
    } catch (error) {
      console.error(`❌ [KitchenService] Errore recupero piatto ${dishId}:`, error);
    }

    // Fallback
    console.warn(`⚠️ [KitchenService] Piatto non trovato: ${dishId}`);
    return {
      name: `Piatto #${dishId.substring(0, 4)}`,
      preparation_time: 15
    };
  }

private async loadKitchenData(force: boolean = false): Promise<void> {
  const now = Date.now();
  if (!force && now - this.lastLoadTime < this.CACHE_TTL) {
    console.log('⏳ [KitchenService] Dati ancora freschi, salto refresh');
    return;
  }

  try {
    const restaurantId = await this.authService.getCurrentRestaurantId();
    if (!restaurantId) {
      console.error('❌ [KitchenService] Nessun restaurant ID trovato');
      this.rawGroups.next([]);
      return;
    }

    console.log('🔍 [KitchenService] Caricamento ordini per restaurant:', restaurantId);

    const { data, error } = await this.supabase
      .from('order_headers')
      .select(`
        id,
        order_number,
        table_id,
        customer_name,
        created_at,
        tables:table_id (
          table_number,
          table_name,
          floor_plan_id,
          restaurant_floor_plans (id, name)
        ),
        comande:comande!order_header_id (
          id,
          comanda_number,
          status,
          created_at,
          order_items (
            id,
            dish_id,
            quantity,
            status,
            item_notes,
            created_at
          )
        )
      `)
      .eq('restaurant_id', restaurantId)
      .in('status', ['active', 'open', 'pending'])
      .order('created_at', { ascending: true });

    if (error) throw error;

    const groups = this.transformData(data || []);
    this.rawGroups.next(groups);
    this.lastLoadTime = now; // aggiorna timestamp

  } catch (error) {
    console.error('❌ [KitchenService] Errore caricamento dati cucina:', error);
    this.rawGroups.next([]);
  }
}

  private transformData(headers: any[]): KitchenGroup[] {
    console.log('🔄 [KitchenService] Trasformazione dati...');
    
    return headers.map(header => {
      // Estrai info mappa
      let floor_plan_id = 'no-floor-plan';
      let floor_plan_name = 'Senza mappa';
      
      if (header.tables) {
        const tableData = Array.isArray(header.tables) ? header.tables[0] : header.tables;
        
        if (tableData?.floor_plan_id) {
          floor_plan_id = tableData.floor_plan_id;
          
          if (tableData.restaurant_floor_plans) {
            const floorPlanData = Array.isArray(tableData.restaurant_floor_plans) 
              ? tableData.restaurant_floor_plans[0]
              : tableData.restaurant_floor_plans;
            
            floor_plan_name = floorPlanData?.name || `Mappa ${floor_plan_id.substring(0, 4)}...`;
          } else {
            floor_plan_name = `Mappa ${floor_plan_id.substring(0, 4)}...`;
          }
        }
      }

      const comande = this.transformComande(header.comande || [], header);
      
      const status_summary = this.calculateGroupStatusSummary(comande);
      
      return {
        order_header_id: header.id,
        order_number: header.order_number,
        table_number: header.tables?.table_number?.toString() || header.table_id,
        table_name: header.tables?.table_name || `Tavolo ${header.table_id}`,
        created_at: header.created_at,
        customer_name: header.customer_name || 'Cliente',
        floor_plan_id,
        floor_plan_name,
        table_id: header.table_id,
        comande,
        status_summary
      };
    });
  }

  private transformComande(comande: any[], header: any): KitchenComanda[] {
    return comande.map(comanda => {
      console.log(`📝 [KitchenService] Trasformazione comanda ${comanda.id}`);
      
      const items: KitchenItem[] = (comanda.order_items || []).map((item: any): KitchenItem => {
        // DEBUG per ogni item
        console.log(`🔍 [KitchenService] Item ${item.id}: dish_id = ${item.dish_id}`);
        
        // Ottieni info piatto
        const dishInfo = this.getDishInfo(item.dish_id);
        
        return {
          id: item.id,
          dish_id: item.dish_id,
          dish_name: dishInfo.name,
          quantity: item.quantity,
          status: item.status || 'ordered',
          notes: item.item_notes || '',
          special_requests: item.item_notes || '',
          created_at: item.created_at,
          preparation_time: dishInfo.preparation_time,
          table_number: header.tables?.table_number || 'N/A'
        };
      });

      const totalItems = items.length;
      const completedItems = items.filter((item: KitchenItem) => 
        ['ready', 'served', 'cancelled', 'out_of_stock'].includes(item.status)
      ).length;
      
      const progressPercentage = totalItems > 0 
        ? Math.round((completedItems / totalItems) * 100) 
        : 0;
      
      return {
        id: comanda.id,
        comanda_number: comanda.comanda_number || 1,
        status: comanda.status || 'ordered',
        created_at: comanda.created_at,
        items,
        completed_items: completedItems,
        total_items: totalItems,
        progress_percentage: progressPercentage
      };
    });
  }


  
}