// kitchen-display.component.ts - VERSIONE COMPLETA
import { Component, OnInit, OnDestroy, inject, ChangeDetectorRef } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Observable, Subscription, map, take } from 'rxjs';

// Services
import { KitchenService } from '../../../services/Ordini/kitchen.service';
import { RecipeService } from '../../../services/Piatti/recipe.service';
import { OrderStateService } from '../../../services/Ordini/order-state.service';
import { DishService } from '../../../services/Piatti/dish.service';
import { LucideAngularModule } from 'lucide-angular';

@Component({
  selector: 'app-kitchen-display',
  templateUrl: './kitchen-display.html',
  styleUrls: ['./kitchen-display.css'],
  standalone: true,
  imports: [CommonModule, FormsModule, LucideAngularModule]
})
export class KitchenDisplay implements OnInit, OnDestroy {
  private kitchenService = inject(KitchenService);
  private orderStatusService = inject(OrderStateService);
  private recipeService = inject(RecipeService);
  private cdr = inject(ChangeDetectorRef);
  private dishService = inject(DishService);
  

  // Cache
  private dishNameCache = new Map<string, string>();
  private allowedStatusesCache = new Map<string, string[]>();
  private elapsedTimeCache = new Map<string, number>();
  private lastCacheUpdate = new Map<string, number>();
  private readonly CACHE_TTL = 30000;
  
  // Proprietà
  floorPlans: {id: string, name: string}[] = []; // 👈 Mantieni questa
  selectedFloorPlanId: string = 'all'; // 👈 Mantieni questa

  recipeDetails$?: Observable<any>;
  statusFilter: string = 'all';
  searchTerm: string = '';
  filteredGroups$ = this.kitchenService.filteredGroups$;
  stats$ = this.kitchenService.stats$;
  showRecipeModal = false;
  selectedRecipeItem: any = null;
  expandedGroups: { [key: string]: boolean } = {};
  expandedComande: { [key: string]: boolean } = {};
  private subscriptions = new Subscription();

async ngOnInit() {
  console.log('🏁 KitchenDisplay initialized');

  // Carica mappe
  await this.loadFloorPlans();

  // Forza il primo refresh
  await this.forceRefresh();

  // Inizializza espansioni (opzionale: tutte espanse)
  // Puoi lasciare gli oggetti vuoti e nel template usare un default (es. true)
  // Oppure, se vuoi che siano tutte espanse, puoi fare:
  this.filteredGroups$.pipe(take(1)).subscribe(groups => {
    groups.forEach(group => {
      this.expandedGroups[group.order_header_id] = true;
      group.comande?.forEach((comanda: any, index: number) => {
        const key = `${group.order_header_id}-${index}`;
        this.expandedComande[key] = true;
      });
    });
  });

  // DEBUG: rimuovi o commenta in produzione
  // this.debugDishNames();
}

  ngOnDestroy() {
    this.subscriptions.unsubscribe();
  }

  async loadFloorPlans(): Promise<void> {
    try {
      this.floorPlans = await this.kitchenService.loadFloorPlans();
    } catch (error) {
      console.error('Errore caricamento mappe:', error);
    }
  }

  // 👇 METODO PER CAMBIARE FILTRO MAPPA
  onFloorPlanChange(): void {
    this.kitchenService.setFloorPlanFilter(this.selectedFloorPlanId);
  }

  // === METODI STATO PIATTI ===
  async startItemPreparation(item: any): Promise<void> {
    const success = await this.orderStatusService.updateItemStatus(item.id, 'preparing');
    if (success) await this.forceRefresh();
    else alert('Errore');
  }

  async markItemAsReady(item: any): Promise<void> {
    const success = await this.orderStatusService.updateItemStatus(item.id, 'ready');
    if (success) await this.forceRefresh();
    else alert('Errore');
  }

  async markItemAsOutOfStock(item: any): Promise<void> {
    const success = await this.orderStatusService.updateItemStatus(item.id, 'out_of_stock');
    if (success) await this.forceRefresh();
    else alert('Errore');
  }

async updateItemStatus(item: any, event: Event, comandaId: string): Promise<void> {
  const selectElement = event.target as HTMLSelectElement;
  const newStatus = selectElement.value;
  
  if (this.orderStatusService.canTransitionItem(item.status, newStatus, 'kitchen')) {
    
    // Passa SEMPRE il comandaId
    const success = await this.orderStatusService.updateItemStatus(item.id, newStatus, comandaId);
    
    if (success) {
      console.log(`✅ Item ${item.id} aggiornato`);
      await this.forceRefresh();
    } else {
      console.error(`❌ Errore aggiornamento item ${item.id}`);
      selectElement.value = item.status;
    }
  } else {
    console.warn(`⛔ Transizione non consentita: ${item.status} → ${newStatus}`);
    selectElement.value = item.status;
    alert('Transizione non consentita!');
  }
}


  // === METODI STATO COMANDA ===
  async updateComandaStatus(comanda: any, event: Event): Promise<void> {
    const selectElement = event.target as HTMLSelectElement;
    const newStatus = selectElement.value;
    
    const success = await this.orderStatusService.updateComandaStatus(comanda.id, newStatus);
    if (success) await this.forceRefresh();
    else selectElement.value = comanda.status;
  }

  async markAllItemsInComandaAsReady(comanda: any): Promise<void> {
    const success = await this.kitchenService.markAllItemsInComandaAsReady(comanda);
    if (success) await this.forceRefresh();
    else alert('Errore');
  }

  // === METODI UI ===
  toggleGroupExpansion(groupId: string) {
    this.expandedGroups[groupId] = !this.expandedGroups[groupId];
  }

  toggleComandaExpansion(groupId: string, comandaNumber: number) {
    const key = `${groupId}-${comandaNumber}`;
    this.expandedComande[key] = !this.expandedComande[key];
  }

  isGroupExpanded(groupId: string): boolean {
    return this.expandedGroups[groupId] !== false;
  }

  isComandaExpanded(groupId: string, comandaNumber: number): boolean {
    const key = `${groupId}-${comandaNumber}`;
    return this.expandedComande[key] !== false;
  }

  // === FILTRI ===
  onStatusFilterChange(filter: string) {
    this.statusFilter = filter;
    this.kitchenService.setStatusFilter(filter);
  }

  onSearchChange() {
    this.kitchenService.setSearchTerm(this.searchTerm);
  }

  // === METODI TESTI E COLORI ===
  getStatusText(status: string): string {
    const statusMap: { [key: string]: string } = {
      'ordered': 'Ordinato', 'waiting': 'In Attesa', 'preparing': 'In Preparazione',
      'ready': 'Pronto', 'served': 'Servito', 'cancelled': 'Cancellato', 'out_of_stock': 'Esaurito'
    };
    return statusMap[status] || status;
  }

  getStatusShortText(status: string): string {
    const statusMap: { [key: string]: string } = {
      'ordered': 'Ordinato', 'waiting': 'Attesa', 'preparing': 'Prep.',
      'ready': 'Pronto', 'served': 'Servito', 'out_of_stock': 'Esaurito'
    };
    return statusMap[status] || status;
  }

  getStatusColor(status: string): string {
    const colorMap: { [key: string]: string } = {
      'waiting': 'warning', 'preparing': 'primary', 'ready': 'success',
      'served': 'secondary', 'ordered': 'info', 'cancelled': 'danger', 'out_of_stock': 'dark'
    };
    return colorMap[status] || 'secondary';
  }

  getGroupStatusColor(group: any): string {
    if (this.getGroupStatusSummary(group).waiting > 0) return 'warning';
    if (this.getGroupStatusSummary(group).preparing > 0) return 'primary';
    if (this.getGroupStatusSummary(group).ready > 0) return 'success';
    return 'secondary';
  }

  getGroupStatusText(group: any): string {
    const summary = this.getGroupStatusSummary(group);
    if (summary.waiting > 0) return 'In Attesa';
    if (summary.preparing > 0) return 'In Preparazione';
    if (summary.ready > 0) return 'Pronto';
    return 'Servito';
  }

  getComandaStatusColor(status: string): string {
    const colorMap: { [key: string]: string } = {
      'ordered': 'info', 'waiting': 'warning', 'preparing': 'primary',
      'ready': 'success', 'served': 'secondary', 'cancelled': 'danger'
    };
    return colorMap[status] || 'secondary';
  }

  // === TEMPO E TIMER ===
  formatTime(timeString: string): string {
    return this.kitchenService.formatTime(timeString);
  }

  getElapsedTimeCached(item: any): number {
    const now = Date.now();
    const cacheKey = item.id;
    const lastUpdate = this.lastCacheUpdate.get(cacheKey) || 0;
    const cachedValue = this.elapsedTimeCache.get(cacheKey);
    
    if (cachedValue !== undefined && (now - lastUpdate) < this.CACHE_TTL) {
      return cachedValue;
    }
    
    const elapsed = this.kitchenService.calculateElapsedTime(item);
    this.elapsedTimeCache.set(cacheKey, elapsed);
    this.lastCacheUpdate.set(cacheKey, now);
    return elapsed;
  }

  getTimerColor(item: any): string {
    const elapsed = this.getElapsedTimeCached(item);
    const totalTime = item.preparation_time || 15;
    if (totalTime === 0) return 'secondary';
    
    const percentage = (elapsed / totalTime) * 100;
    if (percentage < 50) return 'success';
    if (percentage < 75) return 'warning';
    return 'danger';
  }

  getRemainingTime(item: any): number {
    const elapsed = this.getElapsedTimeCached(item);
    const totalTime = item.preparation_time || 15;
    return Math.max(0, totalTime - elapsed);
  }

  // === GRUPPI E COMANDE ===
  hasItemsInGroup(group: any): boolean {
    return group.comande.some((comanda: any) => 
      comanda.items && comanda.items.length > 0
    );
  }


  getGroupStatusSummary(group: any): any {
    if (group.status_summary) return group.status_summary;
    
    const summary = { waiting: 0, preparing: 0, ready: 0, served: 0, ordered: 0, cancelled: 0, out_of_stock: 0 };
    group.comande?.forEach((comanda: any) => {
      comanda.items?.forEach((item: any) => {
        const status = item.status || 'ordered';
        if (summary.hasOwnProperty(status)) summary[status as keyof typeof summary]++;
      });
    });
    return summary;
  }

  getComandaProgress(comanda: any): { completed: number; total: number; percentage: number } {
    return {
      completed: comanda.completed_items || 0,
      total: comanda.total_items || 0,
      percentage: comanda.progress_percentage || 0
    };
  }

  // === RICETTE ===
  getRecipeDetails(): { ingredients: any[], instructions: string, preparationTime: number, dishName?: string } {
    if (!this.selectedRecipeItem) {
      return { ingredients: [], instructions: 'Nessun piatto selezionato', preparationTime: 15 };
    }
    return this.recipeService.getRecipeDetails(this.selectedRecipeItem.dish_id);
  }

  openRecipeModal(item: any) {
    this.selectedRecipeItem = item;
    this.showRecipeModal = true;
    this.recipeDetails$ = this.recipeService.getRecipeDetails$(item.dish_id);
  }

  closeRecipeModal() {
    this.selectedRecipeItem = null;
    this.showRecipeModal = false;
  }

  // === UTILITY ===
getDishDisplayName(item: any): string {
  // 1. Prima cerca nel dishService
  const dish = this.dishService.getDishById(item.dish_id);
  if (dish && dish.name && dish.name !== 'Piatto') {
    return dish.name;
  }

  // 2. Se non trovato, usa dish_name dal item
  if (item.dish_name && item.dish_name !== 'Piatto') {
    return item.dish_name;
  }

  // 3. Fallback
  return `Piatto #${item.dish_id?.substring(0, 8) || '???'}`;
}

  getAllowedStatusesForItem(item: any): string[] {
    const cacheKey = `${item.status}_kitchen`;
    if (this.allowedStatusesCache.has(cacheKey)) return this.allowedStatusesCache.get(cacheKey)!;
    
    const allStatuses = ['waiting', 'preparing', 'ready', 'out_of_stock'];
    const allowed = allStatuses.filter(status => 
      this.orderStatusService.canTransitionItem(item.status, status, 'kitchen')
    );
    
    this.allowedStatusesCache.set(cacheKey, allowed);
    return allowed;
  }

  isComandaEditableByKitchen(comanda: any): boolean {
    return ['ordered', 'waiting', 'preparing', 'ready'].includes(comanda.status);
  }

  canTransitionTo(item: any, targetStatus: string): boolean {
    return this.orderStatusService.canTransitionItem(item.status, targetStatus, 'kitchen');
  }

  async forceOrderedToWaiting(item: any): Promise<void> {
    const success = await this.orderStatusService.updateItemStatus(item.id, 'waiting');
    if (success) await this.forceRefresh();
    else alert('Impossibile forzare lo stato');
  }

  async forceRefresh(): Promise<void> {
    await this.kitchenService.forceRefresh();
  }

  async updateItemStatusQuick(item: any, status: string): Promise<void> {
  try {
    const success = await this.orderStatusService.updateItemStatus(item.id, status);
    if (success) {
      await this.forceRefresh();
    } else {
      alert('Errore nel cambio stato');
    }
  } catch (error) {
    console.error('Errore:', error);
    alert('Errore nel cambio stato');
  }
}

trackByGroup(index: number, group: any) {
  return group?.order_header_id ?? index;
}

trackByComanda(index: number, comanda: any) {
  // usa un id univoco se presente
  return comanda?.id ?? comanda?.comanda_number ?? index;
}

trackByItem(index: number, item: any) {
  return item?.id ?? index;
}



}